     1→<?php
     2→/**
     3→ * AgentPress ContentWriter Agent
     4→ *
     5→ * Generates written content using the Claude API.
     6→ *
     7→ * @package AgentPress
     8→ * @since 1.0.0
     9→ */
    10→
    11→namespace AgentPress\Agents;
    12→
    13→use AgentPress\Parser;
    14→
    15→/**
    16→ * ContentWriter agent class.
    17→ */
    18→class Content_Writer {
    19→
    20→    /**
    21→     * Valid tone options.
    22→     *
    23→     * @var array
    24→     */
    25→    private static $valid_tones = array('formal', 'professional', 'friendly', 'technical', 'creative');
    26→
    27→    /**
    28→     * Default model for content generation.
    29→     *
    30→     * @var string
    31→     */
    32→    private static $default_model = 'claude-3-5-sonnet-20241022';
    33→
    34→    /**
    35→     * Maximum output length in characters.
    36→     *
    37→     * @var int
    38→     */
    39→    const MAX_OUTPUT_LENGTH = 2048;
    40→
    41→    /**
    42→     * Run the ContentWriter agent.
    43→     *
    44→     * @param array $payload Payload containing topic, tone, length, etc.
    45→     * @return array|WP_Error Result with text and tokens_used, or WP_Error on failure.
    46→     */
    47→    public static function run($payload) {
    48→        // Validate required topic field
    49→        if (empty($payload['topic'])) {
    50→            return new \WP_Error(
    51→                'agentpress_content_writer_missing_topic',
    52→                __('Missing required "topic" field.', 'agentpress')
    53→            );
    54→        }
    55→
    56→        // Validate tone if provided
    57→        if (isset($payload['tone']) && !in_array($payload['tone'], self::$valid_tones, true)) {
    58→            return new \WP_Error(
    59→                'agentpress_content_writer_invalid_tone',
    60→                sprintf(
    61→                    /* translators: %s: invalid tone */
    62→                    __('Invalid tone "%s". Valid options: %s', 'agentpress'),
    63→                    $payload['tone'],
    64→                    implode(', ', self::$valid_tones)
    65→                )
    66→            );
    67→        }
    68→
    69→        // Build the prompt
    70→        $prompt = self::build_prompt($payload);
    71→
    72→        // Get API key
    73→        $api_key = agentpress_get_setting('claude_api_key');
    74→        if (empty($api_key)) {
    75→            return new \WP_Error(
    76→                'agentpress_missing_api_key',
    77→                __('Claude API key is not configured.', 'agentpress')
    78→            );
    79→        }
    80→
    81→        // Get model from settings
    82→        $model = agentpress_get_setting('default_model', self::$default_model);
    83→
    84→        // Call Claude API
    85→        $response = self::call_claude_api($api_key, $model, $prompt);
    86→
    87→        if (is_wp_error($response)) {
    88→            return $response;
    89→        }
    90→
    91→        // Extract text from response
    92→        $text = self::extract_text_from_response($response);
    93→
    94→        if (is_wp_error($text)) {
    95→            return $text;
    96→        }
    97→
    98→        // Truncate to max length
    99→        $text = self::truncate_text($text);
   100→
   101→        // Get token count from response
   102→        $tokens_used = isset($response['usage']) && isset($response['usage']['total_tokens'])
   103→            ? $response['usage']['total_tokens']
   104→            : 0;
   105→
   106→        return array(
   107→            'text' => $text,
   108→            'tokens_used' => $tokens_used,
   109→        );
   110→    }
   111→
   112→    /**
   113→     * Build the prompt for Claude.
   114→     *
   115→     * @param array $payload Payload data.
   116→     * @return string Formatted prompt.
   117→     */
   118→    private static function build_prompt($payload) {
   119→        $topic = sanitize_text_field($payload['topic']);
   120→        $tone = isset($payload['tone']) ? sanitize_text_field($payload['tone']) : 'professional';
   121→        $length = isset($payload['length']) ? intval($payload['length']) : 500;
   122→
   123→        $prompt = sprintf(
   124→            "Write content about the following topic: %s\n\n",
   125→            $topic
   126→        );
   127→
   128→        $prompt .= sprintf("Tone: %s\n", $tone);
   129→        $prompt .= sprintf("Target length: approximately %d words\n\n", $length);
   130→
   131→        $prompt .= "Write clear, engaging, and well-structured content. ";
   132→        $prompt .= "Return your response as a JSON object with the following structure:\n";
   133→        $prompt .= "{\"text\": \"your content here\"}\n\n";
   134→        $prompt .= "Only return the JSON object, no additional text.";
   135→
   136→        return $prompt;
   137→    }
   138→
   139→    /**
   140→     * Call the Claude Messages API.
   141→     *
   142→     * @param string $api_key API key.
   143→     * @param string $model Model name.
   144→     * @param string $prompt Prompt text.
   145→     * @return array|WP_Error API response or WP_Error on failure.
   146→     */
   147→    private static function call_claude_api($api_key, $model, $prompt) {
   148→        $url = 'https://api.anthropic.com/v1/messages';
   149→
   150→        $headers = array(
   151→            'Content-Type' => 'application/json',
   152→            'x-api-key' => $api_key,
   153→            'anthropic-version' => '2023-06-01',
   154→        );
   155→
   156→        $body = wp_json_encode(array(
   157→            'model' => $model,
   158→            'max_tokens' => 4096,
   159→            'messages' => array(
   160→                array(
   161→                    'role' => 'user',
   162→                    'content' => $prompt,
   163→                ),
   164→            ),
   165→        ));
   166→
   167→        $response = wp_remote_post($url, array(
   168→            'headers' => $headers,
   169→            'body' => $body,
   170→            'timeout' => 30,
   171→        ));
   172→
   173→        if (is_wp_error($response)) {
   174→            return new \WP_Error(
   175→                'agentpress_api_error',
   176→                sprintf(
   177→                    /* translators: %s: error message */
   178→                    __('API request failed: %s', 'agentpress'),
   179→                    $response->get_error_message()
   180→                )
   181→            );
   182→        }
   183→
   184→        $status_code = wp_remote_retrieve_response_code($response);
   185→        $body = wp_remote_retrieve_body($response);
   186→
   187→        if ($status_code !== 200) {
   188→            $error_data = json_decode($body, true);
   189→            $error_message = isset($error_data['error']) && isset($error_data['error']['message'])
   190→                ? $error_data['error']['message']
   191→                : __('Unknown API error.', 'agentpress');
   192→
   193→            return new \WP_Error(
   194→                'agentpress_api_error',
   195→                sprintf(
   196→                    /* translators: %d: HTTP status code, %s: error message */
   197→                    __('API error %1$d: %2$s', 'agentpress'),
   198→                    $status_code,
   199→                    $error_message
   200→                )
   201→            );
   202→        }
   203→
   204→        return json_decode($body, true);
   205→    }
   206→
   207→    /**
   208→     * Extract text from Claude API response.
   209→     *
   210→     * @param array $response API response.
   211→     * @return string|WP_Error Extracted text or WP_Error on failure.
   212→     */
   213→    private static function extract_text_from_response($response) {
   214→        if (!isset($response['content']) || !is_array($response['content'])) {
   215→            return new \WP_Error(
   216→                'agentpress_invalid_response',
   217→                __('Invalid response format from API.', 'agentpress')
   218→            );
   219→        }
   220→
   221→        // Get text from content blocks
   222→        $text = '';
   223→        foreach ($response['content'] as $block) {
   224→            if (isset($block['type']) && $block['type'] === 'text') {
   225→                $text .= $block['text'];
   226→            }
   227→        }
   228→
   229→        if (empty($text)) {
   230→            return new \WP_Error(
   231→                'agentpress_empty_response',
   232→                __('Empty response from API.', 'agentpress')
   233→            );
   234→        }
   235→
   236→        // Try to extract JSON from the response
   237→        $parsed = Parser::extract_json($text);
   238→        if (is_array($parsed) && isset($parsed['text'])) {
   239→            return $parsed['text'];
   240→        }
   241→
   242→        // Return raw text if no JSON found
   243→        return $text;
   244→    }
   245→
   246→    /**
   247→     * Truncate text to maximum length.
   248→     *
   249→     * @param string $text Text to truncate.
   250→     * @return string Truncated text.
   251→     */
   252→    private static function truncate_text($text) {
   253→        if (strlen($text) <= self::MAX_OUTPUT_LENGTH) {
   254→            return $text;
   255→        }
   256→
   257→        // Truncate at word boundary if possible
   258→        $truncated = substr($text, 0, self::MAX_OUTPUT_LENGTH);
   259→        $last_space = strrpos($truncated, ' ');
   260→
   261→        if ($last_space !== false) {
   262→            $truncated = substr($truncated, 0, $last_space);
   263→        }
   264→
   265→        return $truncated . '...';
   266→    }
   267→}
   268→
   269→/**
   270→ * Handler function for ContentWriter agent.
   271→ *
   272→ * @param array $payload Payload data.
   273→ * @return array|WP_Error Result or WP_Error.
   274→ */
   275→function agentpress_run_content_writer($payload) {
   276→    return Content_Writer::run($payload);
   277→}
